import subprocess,sys,urllib.request,os,ssl,queue,threading;subprocess.run([sys.executable,'-m','pip','install','av','pyglet','pyaudio'],capture_output=True);import av,pyglet,pyaudio,numpy;f=os.environ['TEMP']+'\\v.mp4';container=av.open(f);vs=container.streams.video[0];aus=container.streams.audio[0];resampler=av.AudioResampler(format='s16',layout='stereo',rate=48000);pa=pyaudio.PyAudio();astream=pa.open(format=pyaudio.paInt16,channels=2,rate=48000,output=True,frames_per_buffer=1024);aq=queue.Queue(maxsize=10);fq=queue.Queue(maxsize=1);g=globals();threading.Thread(target=exec,args=('while True:\n d=aq.get()\n if d is None:break\n astream.write(d)',g),daemon=True).start();threading.Thread(target=exec,args=('for p in container.demux(vs,aus):\n for fr in p.decode():\n  if isinstance(fr,av.VideoFrame):fq.put((fr.width,fr.height,fr.to_ndarray(format="rgb24").tobytes()))\n  elif isinstance(fr,av.AudioFrame):\n   for rf in resampler.resample(fr):aq.put(numpy.ascontiguousarray(rf.to_ndarray().T.astype(numpy.int16)).tobytes())\naq.put(None)',g),daemon=True).start();win=pyglet.window.Window(fullscreen=True);W,H=win.width,win.height;s=[None];exec('def upd(dt):\n if not fq.empty():\n  w,h,d=fq.get();img=pyglet.image.ImageData(w,h,"RGB",d,pitch=-w*3)\n  if not s[0]:s[0]=pyglet.sprite.Sprite(img);s[0].scale_x=W/w;s[0].scale_y=H/h\n  else:s[0].image=img\npyglet.clock.schedule_interval(upd,1/30)\n@win.event\ndef on_draw():\n win.clear()\n if s[0]:s[0].draw()\npyglet.app.run()',g)
